def knightDialer(n):
    MOD = 10**9 + 7
    moves = {
        0: [4, 6], 1: [6, 8], 2: [7, 9], 3: [4, 8],
        4: [0, 3, 9], 5: [], 6: [0, 1, 7],
        7: [2, 6], 8: [1, 3], 9: [2, 4]
    }
    dp = {i: 1 for i in range(10)}
    for _ in range(n - 1):
        ndp = {i: 0 for i in range(10)}
        for d in range(10):
            for src in moves[d]:
                ndp[d] = (ndp[d] + dp[src]) % MOD
        dp = ndp
    return sum(dp.values()) % MOD

